#include <vector>
#include <algorithm>

using namespace std;

vector<bool> solve(vector<long long> nums, long long k) {
    int n = nums.size();
    vector<bool> answer(n, false);

    for (int x = 1; x <= n; ++x) {
        vector<long long> capped;
        for (long long num : nums) {
            capped.push_back(min(num, (long long)x));
        }

        vector<bool> dp(k + 1, false);
        dp[0] = true;

        for (long long num : capped) {
            for (long long j = k; j >= num; --j) {
                if (dp[j - num]) {
                    dp[j] = true;
                }
            }
            if (dp[k]) {
                break;
            }
        }

        answer[x - 1] = dp[k];
    }

    return answer;
}
